// ─────────────────────────────────────────────────────────────────────────
// NOTA: el nodo HTTP Request devuelve el HTML en $json.data (response text)
//       Los datos originales de Postgres vienen del input anterior al HTTP.
//       En n8n con SplitInBatches, el item tiene el json original más el
//       resultado del HTTP. Ajusta 'html' según cómo recibas el body:
//         - Si el HTTP node está configurado con responseFormat='text': $json.data
//         - Si es la respuesta directa: $json.body o $json.data
// ─────────────────────────────────────────────────────────────────────────

const items = $input.all();
const results = [];

for (const item of items) {
  const row = item.json;
  // El campo 'data' es el HTML crudo devuelto por el nodo HTTP Request
  const html = String(row.data || row.body || '');

  // ── helpers ──────────────────────────────────────────────────────────
  function tryJson(s) {
    try { return JSON.parse(s); } catch { return null; }
  }

  function safeStr(v) { return v == null ? '' : String(v).trim(); }
  function safeInt(v) { const n = parseInt(v, 10); return isNaN(n) ? null : n; }

  function unesc(s) {
    return String(s || '')
      .replace(/\\"/g, '"')
      .replace(/\\u002F/gi, '/')
      .replace(/\\\/g, '/');
  }

  function deepFind(obj, keys) {
    if (!obj || typeof obj !== 'object') return undefined;
    for (const key of keys) {
      if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') return obj[key];
    }
    for (const val of Object.values(obj)) {
      if (val && typeof val === 'object' && !Array.isArray(val)) {
        const found = deepFind(val, keys);
        if (found !== undefined) return found;
      }
    }
    return undefined;
  }

  function normalizeBodyType(raw) {
    const s = String(raw || '').toLowerCase();
    if (!s) return '';
    if (/suv|crossover|4x4/.test(s)) return 'SUV';
    if (/berlina|sedan|saloon/.test(s)) return 'Berlina';
    if (/familiar|estate|combi|wagon|avant/.test(s)) return 'Familiar';
    if (/coupe|coupé/.test(s)) return 'Coupé';
    if (/cabrio|convert/.test(s)) return 'Cabrio';
    if (/mono|van|mpv/.test(s)) return 'Monovolumen';
    if (/hatchback/.test(s)) return 'Berlina';
    return raw.charAt(0).toUpperCase() + raw.slice(1);
  }

  function normalizeFuel(raw) {
    const s = String(raw || '').toLowerCase();
    if (!s) return '';
    if (/diesel/.test(s)) return 'Diesel';
    if (/gasolin|petrol/.test(s)) return 'Gasolina';
    if (/el[eé]ctric/.test(s)) return 'Eléctrico';
    if (/h[íi]brido|hybrid/.test(s)) return 'Híbrido';
    return raw.charAt(0).toUpperCase() + raw.slice(1);
  }

  function normalizeGear(raw) {
    const s = String(raw || '').toLowerCase();
    if (!s) return '';
    if (/auto|dct|cvt|dsg|tiptronic/.test(s)) return 'Automatica';
    if (/manual/.test(s)) return 'Manual';
    return raw.charAt(0).toUpperCase() + raw.slice(1);
  }

  // Escapa comillas simples para SQL inline
  function esc(v) { return String(v || '').replace(/'/g, "''"); }

  // ── extracción de la página ───────────────────────────────────────────
  const ex = {};
  const content = unesc(html);

  // 1. __NEXT_DATA__
  const nextMatch = html.match(/<script[^>]+id=["']__NEXT_DATA__["'][^>]*>([\s\S]*?)<\/script>/i);
  if (nextMatch) {
    const nd = tryJson(nextMatch[1]);
    if (nd) {
      const props = nd?.props?.pageProps || nd?.props || {};
      const vo = props.vehicle || props.car || props.listing || props.ad ||
                 props.carDetails || props.initialData?.vehicle ||
                 props.dehydratedState?.queries?.[0]?.state?.data || props.pageData;
      if (vo) {
        const ps  = deepFind(vo, ['powerPs', 'powerCV', 'powerCv', 'power_cv', 'ps']);
        const kw  = deepFind(vo, ['powerKw', 'power_kw', 'kw']);
        if (ps)  ex.powerCv = safeInt(ps);
        if (kw)  ex.powerKw = safeInt(kw);
        const bt = deepFind(vo, ['bodyType', 'body_type', 'carType', 'carBodyType']);
        if (bt)  ex.bodyType = normalizeBodyType(bt);
        const fu = deepFind(vo, ['fuelType', 'fuel_type', 'fuel']);
        if (fu)  ex.fuel = normalizeFuel(fu);
        const ge = deepFind(vo, ['gearType', 'transmission', 'gearbox']);
        if (ge)  ex.transmission = normalizeGear(ge);
        const ci = deepFind(vo, ['city', 'hub', 'hubName', 'deliveryCity']);
        if (ci)  ex.city = safeStr(ci);
        const col = deepFind(vo, ['color', 'colorName', 'colourId', 'exteriorColor', 'carColor']);
        if (col) ex.color = safeStr(col);
        const el = deepFind(vo, ['environmentalLabel', 'ecoLabel', 'emissionSticker', 'euroEmissionClass']);
        if (el) ex.envLabel = safeStr(el);
        const dr = deepFind(vo, ['doors', 'numberOfDoors', 'numDoors']);
        if (dr) ex.doors = safeInt(dr);
        const se = deepFind(vo, ['seats', 'numberOfSeats', 'numSeats', 'seatCount']);
        if (se) ex.seats = safeInt(se);
        const di = deepFind(vo, ['displacement', 'engineSize', 'cubicCapacity', 'engineDisplacement']);
        if (di) ex.displacement = safeStr(di);
        const c2 = deepFind(vo, ['co2', 'co2Emissions', 'co2Value', 'emissionCo2']);
        if (c2) ex.co2 = safeStr(c2);
        const cn = deepFind(vo, ['consumption', 'fuelConsumption', 'combinedConsumption', 'consumptionCombined']);
        if (cn != null) ex.consumption = parseFloat(cn);
        const tt = deepFind(vo, ['traction', 'driveType', 'drive', 'wheelDrive', 'drivetrain']);
        if (tt) ex.traction = safeStr(tt);
        const wm = deepFind(vo, ['warrantyMonths', 'warrantyDuration', 'warrantyPeriod']);
        if (wm) ex.warrantyMonths = safeInt(wm);
        const imgs = deepFind(vo, ['images', 'gallery', 'photos', 'imageUrls']);
        if (Array.isArray(imgs) && imgs.length > 0) {
          const urls = imgs.map(i => typeof i === 'string' ? i : i?.url || i?.src || '').filter(Boolean).slice(0, 10);
          if (urls.length > 0) { ex.imageUrl = urls[0]; ex.images = urls; }
        }
      }
    }
  }

  // 2. Patrones JSON inline
  if (!ex.imageUrl) {
    const m = content.match(/"ahMainImageUrl":"([^"]+)"/i)?.[1] ||
              content.match(/"mainImageUrl":"([^"]+)"/i)?.[1] ||
              content.match(/"primaryImageUrl":"([^"]+)"/i)?.[1];
    if (m) { ex.imageUrl = m.replace(/\\/g, ''); ex.images = [ex.imageUrl]; }
  }
  if (!ex.imageUrl) {
    const g = [...content.matchAll(/"(https:\/\/img-eu[^"]+autohero[^"]+)"/gi)];
    if (g.length > 0) {
      const urls = [...new Set(g.map(m => m[1].replace(/\\/g, '')))].slice(0, 10);
      ex.imageUrl = urls[0]; ex.images = urls;
    }
  }
  if (!ex.powerCv) {
    const m = content.match(/"powerPs":(\d+)/i)?.[1] || content.match(/"powerCv":(\d+)/i)?.[1];
    if (m) ex.powerCv = safeInt(m);
  }
  if (!ex.powerKw) {
    const m = content.match(/"powerKw":(\d+)/i)?.[1];
    if (m) ex.powerKw = safeInt(m);
  }
  if (!ex.bodyType) {
    const m = content.match(/"bodyType":"([^"]+)"/i)?.[1] || content.match(/"carType":"([^"]+)"/i)?.[1];
    if (m) ex.bodyType = normalizeBodyType(m);
  }
  if (!ex.fuel) {
    const m = content.match(/"fuelType":"([^"]+)"/i)?.[1];
    if (m) ex.fuel = normalizeFuel(m);
  }
  if (!ex.transmission) {
    const m = content.match(/"gearType":"([^"]+)"/i)?.[1];
    if (m) ex.transmission = normalizeGear(m);
  }
  if (!ex.city) {
    const m = content.match(/"hub(?:Name)?":"([^"]+)"/i)?.[1] || content.match(/"city":"([^"]+)"/i)?.[1];
    if (m) ex.city = safeStr(m);
  }
  if (!ex.color) {
    const m = content.match(/"color":"([^"]+)"/i)?.[1] ||
              content.match(/"colorName":"([^"]+)"/i)?.[1] ||
              content.match(/"exteriorColor":"([^"]+)"/i)?.[1];
    if (m) ex.color = safeStr(m);
  }

  //── powerCv desde kW si no viene directo (1 kW = 1.3596 CV) ─────────
  if (!ex.envLabel) {
    const m = content.match(/"environmentalLabel":"([^"]+)"/i)?.[1] ||
              content.match(/"ecoLabel":"([^"]+)"/i)?.[1] ||
              content.match(/"emissionSticker":"([^"]+)"/i)?.[1];
    if (m) ex.envLabel = safeStr(m);
  }
  if (!ex.doors) {
    const m = content.match(/"(?:numberOfDoors|doors)":(\d+)/i)?.[1];
    if (m) ex.doors = safeInt(m);
  }
  if (!ex.seats) {
    const m = content.match(/"(?:numberOfSeats|seats|seatCount)":(\d+)/i)?.[1];
    if (m) ex.seats = safeInt(m);
  }
  if (!ex.displacement) {
    const m = content.match(/"(?:displacement|engineSize|cubicCapacity)":"([^"]+)"/i)?.[1] ||
              content.match(/"(?:displacement|engineSize|cubicCapacity)":(\d+)/i)?.[1];
    if (m) ex.displacement = safeStr(m);
  }
  if (!ex.co2) {
    const m = content.match(/"co2(?:Emissions|Value)?":(\d+)/i)?.[1];
    if (m) ex.co2 = m;
  }
  if (ex.consumption == null) {
    const m = content.match(/"(?:consumption|fuelConsumption|combinedConsumption)":(\d+\.?\d*)/i)?.[1];
    if (m) ex.consumption = parseFloat(m);
  }
  if (!ex.traction) {
    const m = content.match(/"(?:driveType|drive|wheelDrive|drivetrain)":"([^"]+)"/i)?.[1];
    if (m) ex.traction = safeStr(m);
  }
  if (!ex.warrantyMonths) {
    const m = content.match(/"(?:warrantyMonths|warrantyDuration)":(\d+)/i)?.[1];
    if (m) ex.warrantyMonths = safeInt(m);
  }
  const finalPowerCv = ex.powerCv || (ex.powerKw ? Math.round(ex.powerKw * 1.3596) : null);

  // ── construir SET clauses (solo campos que faltaban y ahora tienen valor) ─
  const sets = [];

  if (!row.image_url && ex.imageUrl) {
    sets.push(`image_url = '${esc(ex.imageUrl)}'`);
    sets.push(`images = '${esc(JSON.stringify(ex.images || [ex.imageUrl]))}'`);
  }
  if ((!row.power_cv || row.power_cv === 0) && finalPowerCv) {
    sets.push(`power_cv = ${finalPowerCv}`);
  }
  if (ex.powerKw) {
    sets.push(`power_kw = ${ex.powerKw}`);
  }
  if (!row.body_type && ex.bodyType) {
    sets.push(`body_type = '${esc(ex.bodyType)}'`);
  }
  if (!row.city && ex.city) {
    sets.push(`city = '${esc(ex.city)}'`);
    sets.push(`province = '${esc(ex.city)}'`);
    sets.push(`location = '${esc(ex.city)}'`);
  } else if (!row.location) {
    sets.push(`location = 'Toda España'`);
  }
  if (!row.color && ex.color) {
    sets.push(`color = '${esc(ex.color)}'`);
  }
  if (!row.fuel && ex.fuel) {
    sets.push(`fuel = '${esc(ex.fuel)}'`);
  }
  if (!row.transmission && ex.transmission) {
    sets.push(`transmission = '${esc(ex.transmission)}'`);
  }
  if (!row.environmental_label && ex.envLabel) {
    sets.push(`environmental_label = '${esc(ex.envLabel)}'`);
  }
  if ((!row.doors || row.doors === 0) && ex.doors) {
    sets.push(`doors = ${ex.doors}`);
  }
  if ((!row.seats || row.seats === 0) && ex.seats) {
    sets.push(`seats = ${ex.seats}`);
  }
  if (!row.displacement && ex.displacement) {
    sets.push(`displacement = '${esc(ex.displacement)}'`);
  }
  if (!row.co2 && ex.co2) {
    sets.push(`co2 = '${esc(ex.co2)}'`);
  }
  if ((!row.consumption || row.consumption === 0) && ex.consumption != null) {
    sets.push(`consumption = ${ex.consumption}`);
  }
  if (!row.traction && ex.traction) {
    sets.push(`traction = '${esc(ex.traction)}'`);
  }
  if ((!row.warranty_months || row.warranty_months === 0) && ex.warrantyMonths) {
    sets.push(`warranty_months = ${ex.warrantyMonths}`);
  }

  const hasUpdates = sets.length > 0;
  const updateSql = hasUpdates
    ? `UPDATE moveadvisor_market_offers SET ${sets.join(', ')}, updated_at = NOW() WHERE id = '${esc(row.id)}'`
    : null;

  results.push({ json: { id: row.id, brand: row.brand, model: row.model, hasUpdates, updateSql } });
}

return results;
